sys_script_include.script:
var BaseTableProvider = Class.create();
BaseTableProvider.prototype = {
    initialize: function (params) {
        params = params || {};

        this.transactionId = params.transactionId || gs.generateGUID();
        this.providerParams = params.providerParams || {};

        this.logger = new Logger({
            transactionId: this.transactionId,
            source: this.type,
            includeTimeStamp: true,
            includeUserInfo: true,
            includeSessionId: true,
        });

        this.configObject = this._initializeConfigObject();
        this.preferenceNames = {
            columns: this.configObject.fields_preference_name,
            orderBy: this.configObject.order_by_preference_name,
            orderDirection: this.configObject.order_direction_preference_name,
            limit: this.configObject.limit_preference_name,
        };
    },

    canCreate: function () {
        try {
            if (this.configObject.show_new_record_button !== "true") {
                return false;
            }

            var gr = new GlideRecordSecure(this.configObject.table);
            return gr.isValid() && gr.canCreate();
        } catch (error) {
            this.logger.error({
                method: "canCreate",
                message: "Error checking create permissions",
                error: error.message,
                table: this.configObject.table,
            });
            return false;
        }
    },

    canFilter: function () {
        return (
            this.configObject.can_filter === "true" &&
            (this.configObject.filter_fields || []).length > 0
        );
    },

    canSavePreferences: function () {
        return this.configObject.can_save_preferences === "true";
    },

    canConfigureColumns: function () {
        return (
            this.configObject.can_configure_columns === "true" ||
            !this.configObject.hasOwnProperty("can_configure_columns")
        );
    },

    getAllAvailableColumns: function () {
        return this.configObject.columns || [];
    },

    getAppliedFiltersInfoMessage: function (appliedFilters) {
        appliedFilters = appliedFilters || [];
        var htmlString = "";

        try {
            for (var i = 0; i < appliedFilters.length; i++) {
                var filter = appliedFilters[i];
                var isLastFilter = i === appliedFilters.length - 1;

                if (filter.type === "reference") {
                    var grRef = new GlideRecord(filter.referenceTable);
                    if (grRef.get(filter.value)) {
                        /* prettier-ignore */
                        htmlString += "<span>" + this._escapeHtml(filter.label) + " = " + this._escapeHtml(grRef.getDisplayValue()) + "</span>";
                    } else {
                        /* prettier-ignore */
                        htmlString += "<span>" + this._escapeHtml(filter.label) + " = " + this._escapeHtml(filter.value) + "</span>";
                    }
                }

                if (filter.type === "choice") {
                    var choiceValues = filter.choiceValues || [];
                    var displayValue = filter.value;

                    for (var j = 0; j < choiceValues.length; j++) {
                        if (choiceValues[j].value === filter.value) {
                            displayValue = choiceValues[j].label;
                            break;
                        }
                    }
                    /* prettier-ignore */
                    htmlString += "<span>" + this._escapeHtml(filter.label) + " = " + this._escapeHtml(displayValue) + "</span>";
                }

                if (filter.type === "string") {
                    /* prettier-ignore */
                    htmlString += "<span>" + this._escapeHtml(filter.label) + " = " + this._escapeHtml(filter.value) + "</span>";
                }

                if (!isLastFilter) {
                    htmlString += '<span class="filter-separator">></span>';
                }
            }
        } catch (error) {
            this.logger.error({
                method: "getAppliedFiltersInfoMessage",
                message: "Error generating applied filters info message",
                error: error.message,
                appliedFilters: appliedFilters,
            });
        }

        return htmlString;
    },

    getBreadcrumbs: function () {
        return this.configObject.breadcrumbs || [];
    },

    getChoiceValues: function (fieldName) {
        var choices = [];

        if (!fieldName) return choices;

        var glideTableHierarchy = new GlideTableHierarchy(
            this.configObject.table,
        );
        var hierarchy = glideTableHierarchy.getTables();
        var iterator = 0;

        do {
            var grTable = new GlideRecord("sys_choice");
            grTable.addQuery("name", hierarchy[iterator]);
            grTable.addQuery("element", fieldName);
            grTable.addQuery("inactive", false);
            grTable.query();

            while (grTable.next()) {
                choices.push({
                    value: grTable.getValue("value"),
                    label:
                        grTable.getValue("label") || grTable.getValue("value"),
                });
            }

            iterator++;
        } while (choices.length === 0 && iterator < hierarchy.length);

        return choices;
    },

    getDefaultColumns: function () {
        return (this.configObject.columns || []).filter(function (column) {
            return column.default === true;
        });
    },

    getDetailViewPage: function () {
        return this.configObject.detail_view_page || "error-404";
    },

    getFilterFields: function () {
        return this.configObject.filter_fields || [];
    },

    getIdField: function () {
        return this.configObject.id_field || "sys_id";
    },

    getPrimaryCellClickAction: function () {
        return {
            type: "link",
            urlField: "_primaryLink",
        };
    },

    getCellContent: function (field, record) {
        return {
            layout: "stack",
            blocks: [{ value: record[field.name] || "" }],
        };
    },

    getOrderBy: function () {
        if (!this.canSavePreferences()) {
            return this.configObject.order_by;
        }

        try {
            var orderByPreference = gs
                .getUser()
                .getPreference(this.preferenceNames.orderBy);

            if (orderByPreference) {
                return orderByPreference;
            }
        } catch (error) {
            this.logger.error({
                method: "getOrderBy",
                message: "Error getting order by",
                error: error.message,
                user: gs.getUserID(),
                preferenceName: this.preferenceNames.orderBy,
            });
        }

        return this.configObject.order_by;
    },

    getOrderDirection: function () {
        if (!this.canSavePreferences()) {
            return this.configObject.order_direction;
        }

        try {
            var orderDirectionPreference = gs
                .getUser()
                .getPreference(this.preferenceNames.orderDirection);

            if (orderDirectionPreference) {
                return orderDirectionPreference;
            }
        } catch (error) {
            this.logger.error({
                method: "getOrderDirection",
                message: "Error getting order direction",
                error: error.message,
                user: gs.getUserID(),
                preferenceName: this.preferenceNames.orderDirection,
            });
        }

        return this.configObject.order_direction;
    },

    getPageTitle: function () {
        return this.configObject.page_title || "";
    },

    getTableColumns: function () {
        if (!this.canSavePreferences()) {
            return this.getDefaultColumns();
        }

        try {
            var fieldsPreferencedByUser = gs
                .getUser()
                .getPreference(this.preferenceNames.columns);

            if (fieldsPreferencedByUser) {
                return JSON.parse(fieldsPreferencedByUser);
            }
        } catch (error) {
            this.logger.error({
                method: "getTableColumns",
                message: "Error getting table columns from preference",
                error: error.message,
                user: gs.getUserID(),
                preferenceName: this.preferenceNames.columns,
            });
        }

        return this.getDefaultColumns();
    },

    getTableData: function (options) {
        options = options || {};
        var filters = options.filters || [];
        var page = options.page || 1;

        try {
            var records = [];
            var tableName = this.configObject.table;
            var limit = this.getTableLimit();
            var firstRow = (parseInt(page, 10) - 1) * parseInt(limit, 10);
            var lastRow = firstRow + parseInt(limit, 10);
            var orderBy = this.getOrderBy();
            var orderDirection = this.getOrderDirection();
            var columns = this.getTableColumns();

            if (columns.length === 0) return records;

            var grRecord = new GlideRecord(tableName);
            this._applyFilters(grRecord, filters);
            grRecord.setLimit(parseInt(limit, 10));
            grRecord.chooseWindow(firstRow, lastRow);

            if (orderDirection === "ASC") {
                grRecord.orderBy(orderBy);
            } else {
                grRecord.orderByDesc(orderBy);
            }

            grRecord.query();

            while (grRecord.next()) {
                var record = this._buildBaseRecord(grRecord, columns);
                var decoratedRecord = this._decorateRecord(record, grRecord);
                records.push(decoratedRecord || record);
            }

            return records;
        } catch (error) {
            this.logger.error({
                method: "getTableData",
                message: "Error getting table data",
                error: error.message,
                filters: filters,
                page: page,
            });
            return [];
        }
    },

    getTableLimit: function () {
        if (!this.canSavePreferences()) {
            return parseInt(this.configObject.limit || 10, 10);
        }

        try {
            var limitPreference = gs
                .getUser()
                .getPreference(this.preferenceNames.limit);

            if (limitPreference) {
                return parseInt(limitPreference, 10);
            }
        } catch (error) {
            this.logger.error({
                method: "getTableLimit",
                message: "Error getting table limit",
                error: error.message,
                user: gs.getUserID(),
                preferenceName: this.preferenceNames.limit,
            });
        }

        return parseInt(this.configObject.limit || 10, 10);
    },

    getTotalRecords: function (filters) {
        filters = filters || [];

        try {
            var gaRecord = new GlideAggregate(this.configObject.table);
            this._applyFilters(gaRecord, filters);
            gaRecord.addAggregate("COUNT");
            gaRecord.query();
            gaRecord.next();

            return parseInt(gaRecord.getAggregate("COUNT"), 10) || 0;
        } catch (error) {
            this.logger.error({
                method: "getTotalRecords",
                message: "Error getting total records",
                error: error.message,
                filters: filters,
            });
            return 0;
        }
    },

    saveUserPreference: function (preferenceName, preferenceValue) {
        if (
            !this.preferenceNames[preferenceName] ||
            preferenceValue === undefined ||
            preferenceValue === null
        ) {
            this.logger.warn({
                preferenceName: preferenceName,
                preferenceValue: preferenceValue,
                message: "Invalid input",
            });
            return;
        }

        gs.getUser().savePreference(
            this.preferenceNames[preferenceName],
            String(preferenceValue),
        );
    },

    showAppliedFilters: function () {
        return (
            this.configObject.show_applied_filters === "true" ||
            !this.configObject.hasOwnProperty("show_applied_filters")
        );
    },

    showTableMetadata: function () {
        return (
            this.configObject.show_table_metadata === "true" ||
            !this.configObject.hasOwnProperty("show_table_metadata")
        );
    },

    _applyFilters: function (glideRecord, filters) {
        filters = filters || [];

        if (
            !glideRecord ||
            typeof glideRecord.addQuery !== "function" ||
            typeof glideRecord.addEncodedQuery !== "function"
        ) {
            this.logger.warn({
                method: "_applyFilters",
                message: "Invalid GlideRecord provided for filtering",
            });
            return;
        }

        if (this.configObject.static_query) {
            glideRecord.addEncodedQuery(this.configObject.static_query);
        }

        for (var i = 0; i < filters.length; i++) {
            var filter = filters[i];

            if (
                !filter ||
                !filter.field ||
                filter.value == null ||
                filter.value === ""
            ) {
                continue;
            }

            switch (filter.type) {
                case "choice":
                case "reference":
                    glideRecord.addQuery(filter.field, filter.value);
                    break;
                case "string":
                    /* prettier-ignore */
                    glideRecord.addQuery(filter.field, "CONTAINS", filter.value);
                    break;
                default:
                    this.logger.warn({
                        method: "_applyFilters",
                        message: "Unknown filter type",
                        filter: filter,
                    });
                    break;
            }
        }
    },

    _escapeHtml: function (value) {
        return String(value == null ? "" : value)
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/\"/g, "&quot;")
            .replace(/'/g, "&#39;");
    },

    _buildBaseRecord: function (glideRecord, columns) {
        var record = {};

        for (var i = 0; i < columns.length; i++) {
            var columnName = columns[i].name;
            record[columnName] = glideRecord.getDisplayValue(columnName) || "";
        }

        record.sys_id = glideRecord.getUniqueValue();

        var primaryAction = this.getPrimaryCellClickAction() || {};
        var urlField = primaryAction.urlField || "_primaryLink";

        if (
            primaryAction.type === "link" &&
            urlField &&
            !record.hasOwnProperty(urlField)
        ) {
            record[urlField] = this._buildPrimaryLink(record);
        }

        return record;
    },

    _buildPrimaryLink: function (record) {
        /* prettier-ignore */
        return ("?id=" + this.getDetailViewPage() + "&scm_record_id=" + (record[this.getIdField()] || ""));
    },

    _decorateRecord: function (record) {
        return record;
    },

    _initializeConfigObject: function () {
        return {};
    },

    type: "BaseTableProvider",
};
